TASK_PREFIX = "[DISPATCH]"


class Dispatcher:
    """Base dispatcher that sends tasks to workers."""

    def __init__(self, name, task_priority=0):
        self.name = name
        self.task_priority = task_priority
        self._done = []

    def dispatch(self, task):
        """Dispatch a task for execution."""
        formatted = f"{TASK_PREFIX} {task}"
        self._done.append(formatted)
        return formatted

    def history(self):
        return list(self._done)

