from .core import Dispatcher


class Worker(Dispatcher):
    """A worker that processes dispatched tasks."""

    def __init__(self, name, capacity=10):
        super().__init__(name)
        self.capacity = capacity

    def dispatch(self, task):
        """Worker dispatch with capacity tracking."""
        task_id = f"w-{len(self._done)}"
        result = super().dispatch(task)
        return {"task_id": task_id, "result": result}

