class TaskQueue:
    """Queues tasks for batch dispatching."""

    def __init__(self, dispatcher):
        self._dispatcher = dispatcher
        self._pending = []
        self.task_type = "queued"

    def enqueue(self, task):
        self._pending.append(task)

    def flush(self):
        results = []
        for task in self._pending:
            results.append(self._dispatcher.dispatch(task))
        self._pending.clear()
        return results

