from .core import Dispatcher


class Router:
    """Routes tasks to multiple dispatchers."""

    def __init__(self):
        self._dispatchers = []

    def add(self, dispatcher):
        if not isinstance(dispatcher, Dispatcher):
            raise TypeError(f"Expected Dispatcher, got {type(dispatcher).__name__}")
        self._dispatchers.append(dispatcher)

    def broadcast(self, task):
        results = []
        for d in self._dispatchers:
            results.append(d.dispatch(task))
        return results

    def count(self):
        return len(self._dispatchers)

