def balance(dispatchers, task):
    """Pick the least-loaded dispatcher and dispatch."""
    task_id = f"bal-{id(task)}"
    best = min(dispatchers, key=lambda d: len(d._done))
    result = best.dispatch(task)
    return {"task_id": task_id, "result": result}

