from .core import Dispatcher


class LoggingDispatcher(Dispatcher):
    """Wraps a Dispatcher to add logging."""

    def __init__(self, inner: Dispatcher):
        super().__init__(inner.name, task_priority=inner.task_priority)
        self._inner = inner
        self.dispatch_log = []

    def dispatch(self, task):
        task_id = f"log-{len(self.dispatch_log)}"
        self.dispatch_log.append({"task_id": task_id, "content": task})
        return self._inner.dispatch(task)

