from .errors import DispatchError


def retry_dispatch(dispatcher, task, max_retries=3):
    """Retry a dispatch up to max_retries times."""
    last_error = None
    task_id = f"retry-{id(task)}"
    for attempt in range(max_retries):
        try:
            return dispatcher.dispatch(task)
        except Exception as e:
            last_error = e
    raise DispatchError(task_id, str(last_error))

