DEFAULTS = {
    "task_priority": 0,
    "task_type": "standard",
    "max_retries": 3,
}


def create_dispatcher(cls, name, **kwargs):
    """Factory: create a Dispatcher subclass with defaults."""
    merged = {**DEFAULTS, **kwargs}
    task_priority = merged.pop("task_priority")
    merged.pop("task_type", None)
    merged.pop("max_retries", None)
    return cls(name, task_priority=task_priority, **merged)

