def validate_dispatch(task, task_type="standard"):
    """Validate a task before dispatching."""
    if not task:
        raise ValueError("Empty task")
    if task_type not in ("standard", "batch", "priority"):
        raise ValueError(f"Unknown task_type: {task_type}")
    return True

