from .core import Dispatcher


class Registry:
    """Registry of named dispatchers."""

    def __init__(self):
        self._registry = {}
        self.dispatch_log = []

    def register(self, name, dispatcher):
        if not isinstance(dispatcher, Dispatcher):
            raise TypeError("Expected Dispatcher")
        self._registry[name] = dispatcher
        self.dispatch_log.append(f"registered:{name}")

    def get(self, name):
        return self._registry.get(name)
